section.code:
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://faion.net/schemas/motion-and-micro-interaction-system.json",
  "title": "Motion and Micro-Interaction System",
  "type": "object",
  "required": [
    "artefact_id",
    "system_id",
    "duration_tokens",
    "easing_tokens",
    "choreography_rules",
    "reduced_motion_policy",
    "perceived_perf_budget_ms",
    "platform_outputs",
    "owners",
    "evidence",
    "status",
    "owner",
    "last_touched",
    "template_version"
  ],
  "properties": {
    "artefact_id": {
      "type": "string",
      "description": "slug + ISO date or UUID",
      "minLength": 1
    },
    "system_id": {
      "type": "string",
      "description": "system_id",
      "minLength": 1
    },
    "duration_tokens": {
      "type": "array",
      "description": "duration_tokens (array)",
      "minItems": 1
    },
    "easing_tokens": {
      "type": "array",
      "description": "easing_tokens (array)",
      "minItems": 1
    },
    "choreography_rules": {
      "type": "array",
      "description": "choreography_rules (array)",
      "minItems": 1
    },
    "reduced_motion_policy": {
      "type": "string",
      "description": "reduced_motion_policy",
      "minLength": 1
    },
    "perceived_perf_budget_ms": {
      "type": "number",
      "description": "perceived_perf_budget_ms (numeric)"
    },
    "platform_outputs": {
      "type": "array",
      "description": "platform_outputs (array)",
      "minItems": 1
    },
    "owners": {
      "type": "string",
      "description": "owners",
      "minLength": 1
    },
    "evidence": {
      "type": "array",
      "description": "{source, citation} pairs anchoring non-trivial fields",
      "minItems": 1
    },
    "status": {
      "type": "string",
      "description": "draft|ready_for_review|approved|archived",
      "minLength": 1
    },
    "owner": {
      "type": "string",
      "description": "single named owner; generic group terms forbidden",
      "minLength": 1
    },
    "last_touched": {
      "type": "string",
      "description": "ISO-8601 timestamp",
      "format": "date-time"
    },
    "template_version": {
      "type": "string",
      "description": "semver matching methodology frontmatter at write time"
    }
  },
  "additionalProperties": false
}
